package com.panini.back.controller; import com.panini.back.dto.AuthDtos.*; import com.panini.back.service.AuthService; import jakarta.validation.Valid; import org.springframework.validation.annotation.Validated; import org.springframework.web.bind.annotation.*; @Validated @RestController @RequestMapping("/api/auth") public class AuthController { private final AuthService auth; public AuthController(AuthService auth){ this.auth=auth; } @PostMapping("/register") public AuthResponse register(@Valid @RequestBody RegisterRequest r){ return auth.register(r); } @PostMapping("/login") public AuthResponse login(@Valid @RequestBody LoginRequest r){ return auth.login(r); } }
